import 'dart:io';import 'package:flutter/cupertino.dart';import 'package:flutter/material.dart';import 'package:get/get.dart';import 'package:get/get_core/src/get_main.dart';import 'package:google_api_availability/google_api_availability.dart';import 'package:package_info_plus/package_info_plus.dart';import 'package:upgrader/upgrader.dart';import 'package:url_launcher/url_launcher.dart';void checkForUpdatesAndShowCustomDialog(BuildContext context) async {  PackageInfo packageInfo = await PackageInfo.fromPlatform();  //App ID from Apple Store Console  final androidStoreURL = await PlayStoreSearchAPI().lookupURLById(    packageInfo.packageName, // Your app’s package name  );  final upgrader = Upgrader(    debugDisplayAlways: true,    debugLogging: true,  );  await upgrader.initialize();  final bool isUpdateAvailable = await upgrader.isUpdateAvailable();  print("IOSURl>>>>"+upgrader.versionInfo!.appStoreListingURL.toString());  if (isUpdateAvailable) {    print("A new update is available!");    show_update_alert(androidUrl: androidStoreURL.toString(), iosUrl: upgrader.versionInfo!.appStoreListingURL.toString());  } else {    print("App is up to date. No custom dialog shown.");  }}show_update_alert({required String androidUrl,required String iosUrl}){  Get.dialog(    CupertinoAlertDialog(      title: Text(        'New version available !',      ),      content: Text(        'Please update for the best experience.',      ),      actions: [        CupertinoDialogAction(          child: Text(            'Later',            style: TextStyle(color: Colors.black,fontSize: 14,fontWeight: FontWeight.normal),          ),          onPressed: () {            Get.back();          },        ),        CupertinoDialogAction(          child: Text(            'Update',            style: TextStyle(color: Colors.red,fontSize: 14,fontWeight: FontWeight.bold),          ),          onPressed: () async {            if (Platform.isAndroid) {              GooglePlayServicesAvailability availability = await GoogleApiAvailability.instance.checkGooglePlayServicesAvailability();              if(availability==GooglePlayServicesAvailability.success){                _launchUrl(androidUrl);              }else{                _launchUrl(androidUrl);              }              // _launchUrl(url)              //Navigator.of(context).pop();            }else{              _launchUrl(iosUrl);            }          },        ),      ],    ),  );}Future<void> _launchUrl(String url) async {  if (!await launchUrl(Uri.parse(url),mode: LaunchMode.externalApplication)) {    throw Exception('Could not launch $url');  }}